-- Table structure for table `interview_sessions`
--

DROP TABLE IF EXISTS `interview_sessions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `interview_sessions` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '面试会话ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID，关联users表',
  `student_id` bigint(20) DEFAULT NULL COMMENT '学生ID，关联students表',
  `mode` varchar(50) NOT NULL COMMENT '面试模式：practice-练习模式, assessment-评估模式',
  `status` varchar(50) NOT NULL DEFAULT 'running' COMMENT '状态：running-进行中, completed-已完成, cancelled-已取消',
  `total_questions` int(11) DEFAULT 0 COMMENT '总问题数',
  `current_question` int(11) DEFAULT 0 COMMENT '当前问题序号',
  `average_score` decimal(5,2) DEFAULT 0.00 COMMENT '平均分数',
  `max_score` decimal(5,2) DEFAULT 0.00 COMMENT '最高分数',
  `min_score` decimal(5,2) DEFAULT 0.00 COMMENT '最低分数',
  `duration_seconds` int(11) DEFAULT 0 COMMENT '面试时长（秒）',
  `created_at` bigint(20) NOT NULL COMMENT '创建时间',
  `updated_at` bigint(20) NOT NULL COMMENT '更新时间',
  `completed_at` bigint(20) DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_status` (`status`),
  KEY `idx_created` (`created_at`),
  KEY `idx_user_status` (`user_id`,`status`),
  KEY `idx_interview_sessions_created_desc` (`created_at` DESC),
