INSERT INTO `resume_parse_history` VALUES
(1,10,NULL,'黑白设计通用国际贸易财务会计专业简历.docx','简小历 简小历 出生年月：20 06 . 8 手机：180 0000 1108 工作年限：应届毕业生（0年） 邮箱： jianlixiazai.cn 求职意向： Golang 软件开发岗 地址：广东省珠海市区 教育背景 教育背景 20 24 .XX – 20 28 .XX 浙江师范 大学 软件工程 专业 / 本科 主修课程 Golang 程序设计，rust 程序设计 , 现代web开发，云原生开发，操作系统 实习经历 实习经历 20 24 .XX – 20 25 .XX 分布式博客系统 工作描述 基于 Golang + Gin 框架开发后端服务，设计并实现用户认证、文章发布、评论管理等核心模块，结合 JWT 完成身份鉴权； 使用 GORM 实现 MySQL 数据库交互，优化慢查询，提升接口响应效率； 基于 Redis 实现缓存层，降低数据库访问压力，并利用 RabbitMQ 处理异步任务，提升系统吞吐能力。 20 25 .XX – 20 26 .XX 云原生微服务 Demo 工作描述 基于 Go Kit 构建微服务架构，实现服务注册与发现（Consul）、负载均衡及熔断机制； 使用 Docker 容器化部署服务，编写 docker-compose 编排多服务环境； 引入 Prometheus + Grafana 进行服务监控，搭建基础可观测性体系 个人技能 个人技能 语言能力：英语通过 4 ,6 级考试，口语流利、普通话：流利 计算机能力：熟悉 Golang 编程、Git 协作流程，熟练使用 Linux 常用命令及 Docker 容器化工具 荣誉证书：校奖学金、软件工程专业课程优秀项目奖 个人评价 个人评价 积极主动，热爱技术，对 Golang 及云原生生态有浓厚兴趣。在校期间系统学习 Golang 程序设计、云原生开发等课程，并独立完成多个 Go 项目，具备良好的编码习惯与问题排查能力。乐于钻研源码与新技术，适应团队协作，善于沟通，致力于在 Golang 后端开发方向持续深耕','{\"id\":1774617627229468573,\"userId\":10,\"name\":\"简小历\",\"education\":\"bachelor\",\"major\":\"软件工程\",\"graduationYear\":2028,\"skills\":[{\"name\":\"Golang\",\"level\":85,\"years\":2},{\"name\":\"Gin\",\"level\":80,\"years\":1},{\"name\":\"GORM\",\"level\":75,\"years\":1},{\"name\":\"MySQL\",\"level\":75,\"years\":1},{\"name\":\"Redis\",\"level\":70,\"years\":1},{\"name\":\"RabbitMQ\",\"level\":65,\"years\":1},{\"name\":\"Go Kit\",\"level\":70,\"years\":1},{\"name\":\"Consul\",\"level\":65,\"years\":1},{\"name\":\"Docker\",\"level\":75,\"years\":1},{\"name\":\"Prometheus\",\"level\":60,\"years\":1},{\"name\":\"Grafana\",\"level\":60,\"years\":1},{\"name\":\"Linux\",\"level\":70,\"years\":2},{\"name\":\"Git\",\"level\":80,\"years\":2},{\"name\":\"Rust\",\"level\":60,\"years\":1}],\"certificates\":[{\"name\":\"大学英语四级\",\"level\":\"通过\",\"year\":0},{\"name\":\"大学英语六级\",\"level\":\"通过\",\"year\":0},{\"name\":\"校奖学金\",\"level\":\"校级\",\"year\":0},{\"name\":\"软件工程专业课程优秀项目奖\",\"level\":\"院级\",\"year\":0}],\"softSkills\":{\"innovation\":75,\"learning\":85,\"pressure\":70,\"communication\":75,\"teamwork\":80},\"internship\":[],\"projects\":[{\"name\":\"分布式博客系统\",\"role\":\"开发者\",\"description\":\"基于 Golang + Gin 框架开发后端服务，设计并实现用户认证、文章发布、评论管理等核心模块，结合 JWT 完成身份鉴权；使用 GORM 实现 MySQL 数据库交互，优化慢查询，提升接口响应效率；基于 Redis 实现缓存层，降低数据库访问压力，并利用 RabbitMQ 处理异步任务，提升系统吞吐能力。\",\"technologies\":[\"Golang\",\"Gin\",\"JWT\",\"GORM\",\"MySQL\",\"Redis\",\"RabbitMQ\"]},{\"name\":\"云原生微服务 Demo\",\"role\":\"开发者\",\"description\":\"基于 Go Kit 构建微服务架构，实现服务注册与发现（Consul）、负载均衡及熔断机制；使用 Docker 容器化部署服务，编写 docker-compose 编排多服务环境；引入 Prometheus + Grafana 进行服务监控，搭建基础可观测性体系。\",\"technologies\":[\"Go Kit\",\"Consul\",\"Docker\",\"docker-compose\",\"Prometheus\",\"Grafana\"]}],\"completeness\":70,\"competitiveness\":75,\"suggestions\":[\"内容方面：简历中‘实习经历’部分标题下实际描述的是项目经历，建议将‘分布式博客系统’和‘云原生微服务 Demo’移至‘项目经历’部分，并补充真实的公司实习经历，包括公司名称、职位、时长和具体工作内容，这是求职Golang开发岗的重要加分项。\",\"格式方面：优化简历结构，明确区分‘实习经历’与‘项目经历’。当前‘实习经历’标题下的内容应归类为项目。同时，建议将‘个人评价’内容提炼为更简洁、更具针对性的‘专业技能总结’或‘求职意向陈述’，并置于简历前部。\",\"技能方面：建议在技能描述中量化成果，例如在项目描述中补充性能提升的具体数据（如‘接口响应时间降低XX%’）。同时，可以补充对Kubernetes、CI/CD等云原生核心技术的了解或学习计划，以增强竞争力。\",\"表达方面：提升描述的清晰度和专业性。例如，‘工作描述’应改为‘项目描述’或‘职责描述’。‘个人技能’部分可将‘计算机能力’细分为‘编程语言’、‘开发框架’、‘数据库’、‘工具’等类别，使技能展示更结构化。\"],\"createdAt\":1774617627,\"updatedAt\":1774617627}','[\"内容方面：简历中‘实习经历’部分标题下实际描述的是项目经历，建议将‘分布式博客系统’和‘云原生微服务 Demo’移至‘项目经历’部分，并补充真实的公司实习经历，包括公司名称、职位、时长和具体工作内容，这是求职Golang开发岗的重要加分项。\",\"格式方面：优化简历结构，明确区分‘实习经历’与‘项目经历’。当前‘实习经历’标题下的内容应归类为项目。同时，建议将‘个人评价’内容提炼为更简洁、更具针对性的‘专业技能总结’或‘求职意向陈述’，并置于简历前部。\",\"技能方面：建议在技能描述中量化成果，例如在项目描述中补充性能提升的具体数据（如‘接口响应时间降低XX%’）。同时，可以补充对Kubernetes、CI/CD等云原生核心技术的了解或学习计划，以增强竞争力。\",\"表达方面：提升描述的清晰度和专业性。例如，‘工作描述’应改为‘项目描述’或‘职责描述’。‘个人技能’部分可将‘计算机能力’细分为‘编程语言’、‘开发框架’、‘数据库’、‘工具’等类别，使技能展示更结构化。\"]',70,75,1774617627);
